<template><div class="message" :class="item.sender"><div class="message-row"><div class="message-avatar"><img v-if="item.senderAvatar" :src="item.senderAvatar" alt=""/><span v-else>{{initial}}</span></div><div class="message-body"><strong>{{item.senderName||fallbackName}}</strong><div class="bubble"><a v-if="item.type==='image'" :href="item.url" target="_blank"><img :src="item.thumbnailUrl||item.url" :alt="item.fileName||'图片'" style="max-width:240px;max-height:240px;border-radius:8px"></a><video v-else-if="item.type==='video'" :src="item.url" :poster="item.thumbnailUrl" controls preload="metadata" style="max-width:280px"></video><a v-else-if="item.type==='file'" :href="item.url" target="_blank">📎 {{item.fileName||item.content}} ({{size}})</a><template v-else>{{item.content}}</template></div><small v-if="item.sender==='seller'">{{item.readText || (item.read?'已读':'未读')}}</small></div></div></div></template><script setup lang="ts">import{computed}from'vue';const props=defineProps<{item:any}>();const fallbackName=computed(()=>props.item.sender==='seller'?'卖家':'买家');const initial=computed(()=>(props.item.senderName||fallbackName.value).slice(0,1));const size=computed(()=>props.item.size?`${(props.item.size/1024/1024).toFixed(1)} MB`:'')</script>
